const e=JSON.parse('{"key":"v-85b85a8e","path":"/%E9%9A%8F%E7%AC%94/%E8%80%81%E6%B4%BB%E7%A1%AC%E6%95%B4/%E5%AD%A6%E4%B9%A0%E8%AE%B0%E5%BD%95/gitpage.html","title":"gitpage","lang":"zh-CN","frontmatter":{"icon":"article","author":"$1x6VI","isOriginal":true,"date":"2023-05-26T00:00:00.000Z","category":["组件"],"tag":["部署","gitpage"],"article":false,"timeline":false},"headers":[{"level":2,"title":"github 部署 page","slug":"github-部署-page","link":"#github-部署-page","children":[]}],"git":{"createdTime":1685113381000,"updatedTime":1685113381000,"contributors":[{"name":"$1x6VI","email":"xiaomaohuifaguang@163.com","commits":1}]},"readingTime":{"minutes":0.63,"words":189},"filePathRelative":"随笔/老活硬整/学习记录/gitpage.md","localizedDate":"2023年5月26日","excerpt":"<h1> gitpage</h1>\\n<h2> github 部署 page</h2>\\n<ol>\\n<li>生成个人令牌\\n<ul>\\n<li>github -&gt; setting -&gt; Developer settings -&gt; Personal access tokens -&gt; Token(classic)</li>\\n<li>选择 Generate new token -&gt; Generate new token(classic)</li>\\n<li>Note:起一个别名</li>\\n<li>Expiration:令牌过期时间 注：长一点好，但不要永久</li>\\n<li>勾选 repo里全部 和 workflow</li>\\n<li>拉到最下边 -&gt; 点击 Generate token</li>\\n<li>复制令牌</li>\\n</ul>\\n</li>\\n<li>配置仓库Actions令牌\\n<ul>\\n<li>进入代码仓库 -&gt; Settings -&gt; Secrets and variables -&gt; Actions</li>\\n<li>点击 New repository secret</li>\\n<li>Name: 名称 注意：不要起名 GITHUB_TOKEN</li>\\n<li>Secret: 粘贴刚才的令牌进去</li>\\n<li>点击 Add secret</li>\\n</ul>\\n</li>\\n<li>配置代码workflow\\n<ul>\\n<li>替换GITHUB_TOKEN 其中 secrets.GITHUB_TOKEN 替换为第二步在仓库中配置的名称</li>\\n</ul>\\n</li>\\n</ol>","copyright":{"author":"小猫会发光"}}');export{e as data};
